INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Жаропонижающие', 'Russia', 'Россия', 'Парацетамол', 'Парацетамол',
        'Парацетамол обладает жаропонижающим и болеутоляющим действием.',
        'Болевой синдром различного генеза (головная и зубная, мигрень, миалгия, меналгия, артралгия); лихорадка при инфекционно-воспалительных заболеваниях; плохая переносимость производных салициловой кислоты.',
        'Гиперчувствительность, выраженные нарушения функции печени иили почек, анемия, алкоголизм, беременность (I триместр).', 'Внутрь. Взрослым и подросткам старше 12 лет по 1–2 табл. до 4 раз в день (не более 4 г в сутки).

Детям в возрасте 6–12 лет — по 0,5–1 табл. 4 раза в сутки, до 6 лет (с 3 мес) — 10 мгкг.', TRUE, FALSE, TRUE, TRUE,
        TRUE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Жаропонижающие', 'Russia', 'Россия', 'Терафлю', 'Парацетамол',
        'Терафлю предназначен для симптоматического лечения простуды и гриппа. Помогает снизить температуру и облегчить боль,',
        'Симптоматическая терапия инфекционно-воспалительных заболеваний ОРВИ, в том числе гриппа и простуды, сопровождающихся высокой температурой, ознобом, головной болью, болью в горле, насморком, заложенностью носа, чиханием и болями в мышцах.',
        'Повышенная чувствительность к отдельным компонентам препарата, одновременный прием трициклических антидепрессантов, бета-адреноблокаторов или других симпатомиметических препаратов, одновременный или в течение предшествующих 2 недель прием ингибиторов моноаминоксидазы (МАО), портальная гипертензия, алкоголизм, сахарный диабет, дефицит сахаразыизомальтазы, непереносимость фруктозы, глюкозо-галактозная мальабсорбция, беременность, период грудного вскармливания, детский возраст до 12 лет, тяжелые сердечно-сосудистые заболевания, артериальная гипертензия, гипертиреоз, закрытоугольная глаукома, феохромоцитома.',
        'Внутрь. Взрослые (включая пожилых) и дети 12 лет и старше По одному пакетику каждые 4-6 часов, по мере необходимости, но не более 4 доз в течение 24 часов. Один пакетик растворяют в стакане горячей, но не кипящей воды.',
        TRUE, FALSE, FALSE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Жаропонижающие', 'Russia', 'Россия', 'Эффералган', 'Парацетомол',
        'Эффералган применяется для снижения температуры и облегчения боли, таких как головная боль, зубная боль, мышечная боль и боль при простуде.', 'Болевой синдром слабой или умеренной интенсивности головная боль, зубная боль, мигрень, невралгия, боль в мышцах, боли в пояснице, боль при травмах и ожогах, боли в горле, альгодисменорея;
повышенная температура тела при простудных и других инфекционно-воспалительных заболеваниях.', 'хронический алкоголизм;
дефицит глюкозо-6-фосфатдегидрогеназы;
I и III триместры беременности;
период лактации (грудного вскармливания);
детский возраст до 12 лет (масса тела менее 50 кг);
повышенная чувствительность к компонентам препарата.', 'Обычно применяют по 1–2 таблетки 2–3 раза в сутки с интервалами не менее 4 ч.
Максимальная разовая доза составляет 2 табл. (1 г), максимальная суточная — 8 табл. (4 г), что соответствует для максимальной разовой дозы 10–15 мгкг, для максимальной суточной — 75 мгкг.
Режим дозирования у детей старше 12 лет и массой тела более 43 кг такой же, как у взрослых, при этом интервал должен составлять предпочтительно 6 ч (строго не менее 4 ч).',
        TRUE, FALSE, FALSE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Жаропонижающие', 'Russia', 'Россия', 'Ибупрофен', 'Ибупрофен',
        'Ибупрофен это препарат, который относится к группе противовоспалительных и обезболивающих средств. Он широко используется для снижения температуры, облегчения боли и снятия воспаления', 'Ибупрофен применяется как обезболивающее и противовоспалительное средство при лечении ревматоидного артрита, анкилозирующего спондилита, остеоартроза и других неревматоидных (серонегативных) артропатий.
Ибупрофен показан для лечения неревматических воспалительных процессов периартикулярных тканей, также может быть использован для облегчения болевого синдрома при повреждении мягких тканей, таких как растяжения связок.
Ибупрофен также показан в качестве обезболивающего средства для купирования слабого и умеренного болевого синдрома при таких состояниях, как дисменорея, зубная или послеоперационная боль, для симптоматического облегчения головной боли, в том числе мигрени.', 'Ибупрофен противопоказан пациентам с повышенной чувствительностью к активному или вспомогательным веществам препарата.
Ибупрофен также противопоказан пациентам с желудочно-кишечным кровотечением или перфорацией в анамнезе, связанной с предыдущей терапией ибупрофеном.
Ибупрофен не должен применяться больными с рецидивирующей язвенной болезнью или желудочно-кишечным кровотечением
Ибупрофен противопоказан пациентам с тяжелой сердечной недостаточностью, печеночной и почечной недостаточностью.
Ибупрофен противопоказан во время последнего триместра беременности.', 'Взрослые рекомендуемая дозировка ибупрофена составляет 1200-1800 мг в день, в несколько приемов. Некоторые пациенты могут принимать 600-1200 мг ибупрофена в день.
Дети суточная доза ибупрофена составляет 20 мгкг массы тела, в несколько приемов.', TRUE, FALSE, TRUE, TRUE, TRUE,
        FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Жаропонижающие', 'Russia', 'Россия', 'Нурофен', 'Ибупрофен',
        'Нурофен применяется для снижения температуры, облегчения боли и снятия воспаления',
        'Нурофен применяют при головной боли, мигрени, зубной боли, болезненных менструациях, невралгии, боли в спине, мышечной боли, ревматической боли и боли в суставах; а также при лихорадочном состоянии при гриппе и простудных заболеваниях.', 'Гиперчувствительность к ибупрофену или любому из компонентов, входящих в состав препарата.
Полное или неполное сочетание бронхиальной астмы.
Эрозивно-язвенные заболевания органов желудочно-кишечного тракта.
Кровотечение или перфорация язвы желудочно-кишечного тракта в анамнезе.
Тяжелая сердечная недостаточность.
Тяжелая печеночная недостаточность или заболевание печени в активной фазе.
Почечная недостаточность тяжелой степени тяжести.
Декомпенсированная сердечная недостаточность.
Непереносимость фруктозы, глюкозо-галактозная мальабсорбция, недостаточность сахаразы-изомальтазы.
Hарушения свертываемости крови (в том числе гипокоагуляция), геморрагические диатезы.
Беременность в сроке более 20 недель.', 'Пациентам с повышенной чувствительностью желудка рекомендуется принимать препарат во время еды. Взрослым и детям старше 12 лет внутрь по 1 таблетке (200 мг) до 3-4 раз в сутки.
Детям от 6 до 12 лет по 1 таблетке (200 мг) до 3-4 раз в день; препарат можно принимать только в случае массы тела ребенка более 20 кг. Интервал между приемом таблеток должен составлять не менее 6 часов. Максимальная суточная доза для взрослых составляет 1200 мг (6 таблеток). Максимальная суточная доза для детей от 6 до 18 лет 800 мг (4 таблетки).',
        TRUE, FALSE, TRUE, TRUE, TRUE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От насморка', 'Russia', 'Россия', 'Аква-марис', 'Вода адриатического моря с натуральными микроэлементами',
        'Лекарственный препарат, который используется для ухода за носовой полостью.Помогает очистить носовые проходы, увлажнить слизистую оболочку и облегчить дыхание.', 'Острые и хронические воспалительные заболевания полости носа, придаточных пазух и носоглотки, аденоиды.
Сухость слизистой оболочки полости носа; сохранение физиологических характеристик слизистой оболочки полости носа',
        'Повышенная чувствительность к компонентам препарата.', 'Аквамарис капли назальные для детей
детям с 1 дня жизни 4 раза в день по 2 капли в каждый носовой ход;
Аквамарис спрей детям с 1 года до 7 лет 4 раза в день по два впрыскивания в каждый носовой ход;
детям с 7 до 16 лет 4-6 раз в день по два впрыскивания в каждый носовой ход; взрослым 4-8 раз в день по два-три впрыскивания в каждый носовой ход.',
        TRUE, TRUE, TRUE, TRUE, TRUE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От насморка', 'Russia', 'Россия', 'Називин', 'Оксиметазолина гидрохлорид',
        'Используется для сужения сосудов в носу, что помогает снизить заложенность носа и облегчить дыхание.',
        'Евстахиит, аллергический ринит, вазомоторный ринит, средний отит', 'Атрофический ринит; закрытоугольная глаукома; детский возраст до 6 лет (капли и спрей назальный 0.05%);
повышенная чувствительность к компонентам препарата.',
        'Дети до 1 года дети в возрасте до 4 недель назначают по 1 капле Називина 0,01% в каждый носовой ход 2-3 раза в день. С 5-ой недели жизни и до 1 года - по 1-2 капли в каждый носовой ход 2-3 раза в день.',
        TRUE, TRUE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От насморка', 'Russia', 'Россия', 'Ксилен', 'Ксилометазолин',
        'Лекарственный препарат, который содержит ксилометазолин. Он также используется для сужения сосудов в носу и снижения заложенности носа.',
        'Применяют при острых респираторных заболеваниях с явлениями ринита (насморка), остром аллергическом рините, синуситах, при среднем отите (в составе комбинированной терапии для уменьшения отека слизистой носоглотки), для облегчения проведения риноскопии.',
        'Повышенная чувствительность к ксилометазолину и другим компонентам препарата, артериальная гипертензия, тахикардия, выраженный атеросклероз, глаукома, атрофический ринит, хирургические вмешательства на мозговых оболочках (в анамнезе), беременность, период лактации, детский возраст до 6-х лет - для 0,1% раствора (0,001 гмл).', 'Взрослым и детям старше 6 лет вводят по 1-2 капли 0,1% раствора ксилометазолина в каждый носовой ход 2-3 раза в сутки.
Для грудных детей и детей в возрасте до 6 лет применяют 0,05% раствор по 1-2 капли в каждый носовой ход 1-2 раза в сутки. Не следует применять препарат чаще 3 раз в сутки и не более 3-5 дней.
Не применять препарат без перерыва более 3-5 дней.', TRUE, FALSE, FALSE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От насморка', 'Russia', 'Россия', 'Риностоп', 'Ксилометазолин',
        'Лекарственный препарат, который содержит ксилометазолин. Он применяется для сужения сосудов в носу и снижения заложенности носа.',
        'Острые респираторные заболевания с явлениями ринита (насморка), острый аллергический ринит, поллиноз, синусит, евстахиит, средний отит (в составе комбинированной терапии для уменьшения отека слизистой оболочки носоглотки).',
        'Гиперчувствительность к ксилометазолину или любому из вспомогательных веществ препарата; артериальная гипертензия; тахикардия; выраженный атеросклероз; глаукома; гипертиреоз; атрофический ринит; воспалительные заболевания кожи или слизистой оболочки преддверия носа; хирургические вмешательства на мозговых оболочках (в анамнезе); состояние после транссфеноидальной гипофизэктомии; беременность; применение ингибиторов моноаминоксидазы (МАО) (включая 14 дней после их отмены), трициклических или тетрациклических антидепрессантов; детский возраст до 6 лет (для 0,1 % раствора); детский возраст до 2-х лет (для 0,05 % раствора).',
        'У детей старше 6 лет и взрослых по 1 впрыскиванию в каждый носовой ход 0,1 % раствора 2-3 раза в сутки. У детей в возрасте от 2 до 6 лет по 1 впрыскиванию в каждый носовой ход 0,05 % раствора 1-3 раза в сутки. Не следует применять препарат более 3-х раз в сутки. Не рекомендуется применение лекарственного препарата более 5-7 дней.',
        TRUE, FALSE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От насморка', 'Russia', 'Россия', 'Отривин', 'Ксилометазолин',
        'Лекарственный препарат, который содержит ксилометазолин. Он также используется для сужения сосудов в носу и снижения заложенности носа.',
        'Острые респираторные заболевания с явлениями ринита (насморка), острый аллергический ринит, поллиноз, синусит, евстахиит, средний отит (для уменьшения отека слизистой носоглотки). Подготовка больного к диагностическим манипуляциям в носовых ходах.',
        'Повышенная чувствительность к ксилометазолину и другим компонентам препарата, артериальная гипертензия, тахикардия, выраженный атеросклероз, глаукома, атрофический ринит, гипертиреоз, состояние после транссфеноидальной гипофизэктомии, хирургические вмешательства на мозговых оболочках (в анамнезе). Детский возраст-до 12 лет.', 'Интраназально.
Взрослые и дети старше 12 лет по 1 впрыскиванию в каждый носовой ход 3 раза в сутки.
Не следует применять более 3 раз в сутки.', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От боли в горле', 'Russia', 'Россия', 'Тантум-верде', 'бензидамин',
        'Лекарственный препарат, который содержит бензидамин. Он обладает противовоспалительным и антисептическим действием и применяется для лечения заболеваний горла и полости рта, таких как фарингит, тонзиллит, стоматит и гингивит.', 'Симптоматическая терапия болевого синдрома воспалительных заболеваний полости рта и ЛОР-органов (различной этиологии)
гингивит, глоссит, стоматит (в т.ч. после лучевой и химиотерапии);фарингит, ларингит, тонзиллит; кандидоз слизистой оболочки полости рта (в составе комбинированной терапии); калькулезное воспаление слюнных желез; после оперативных вмешательств и травм (тонзиллэктомия, переломы челюсти); после лечения и удаления зубов; пародонтоз.',
        'Повышенная чувствительность к бензидамину или другим компонентам препарата. Детский возраст до 3 лет.',
        'Спрей для местного применения дозированный 0,51 мгдоза взрослым назначают по 2-4 дозы 2-6 раз в день. Для использования спрея поднимите канюлю, введите ее в полость рта и направьте в область воспаления; нажмите на колпачок (отмечено стрелкой). Бензидамин адгезируется на слизистой оболочке и, благодаря этому, дает стойкий эффект.',
        TRUE, TRUE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От боли в горле', 'Russia', 'Россия', 'Септолете-тотал', 'Деквалиния хлорид, бензокаин',
        'Лекарственный препарат содержит антисептик и анестетик, который помогает снять боль и устранить воспаление в горле. Септолет Тотал применяется для симптоматического лечения заболеваний горла, таких как фарингит и тонзиллит.',
        'Симптоматическая терапия болевого синдрома воспалительных заболеваний полости рта и ЛОР-органов (различной этиологии),в том числе тонзиллитов,фарингитов,в составе комплексной терапии.',
        'Повышенная чувствительность к действующим веществам, либо к любым вспомогательным компонентам препарата; детский возраст до 6 лет.', 'Таблетки следует медленно рассасывать во рту каждые 3-6 часов.
Взрослые, пациенты пожилого возраста и дети старше 12 лет
Рекомендованная доза составляет 3-4 таблетки в сутки.
Дети от 6 до 12 лет
Рекомендованная доза составляет 3 таблетки в сутки.', TRUE, FALSE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От боли в горле', 'Russia', 'Россия', 'Фаринорм', 'Гексетидин',
        'Лекарственный препарат, который содержит антисептик и анестетик. Он применяется для лечения заболеваний горла, таких как фарингит и тонзиллит. Гексарал помогает снять боль, устранить воспаление и убить бактерии в горле.', 'В качестве симптоматического средства при лечении инфекционно-воспалительных заболеваний полости рта и глотки
тонзиллит; ангина; фарингит; гингивит; стоматит; глоссит; пародонтоз; грибковые заболевания.',
        'Повышенная чувствительность к любому из компонентов препарата; - эрозивно-десквамозные поражения слизистой оболочки полости рта; - детский возраст до 3 лет.', 'Раствор.
Взрослым и детям в возрасте старше 6 лет наполнить мерный стаканчик до отметки 15 мл и полоскать полость рта и глотки неразведенным раствором не менее 30 сек, 2-3 разасут.Таблетку следует медленно рассасывать во рту до полного растворения.
Таблетки.
Взрослые и дети старше 12 лет как правило, назначают по 1 таб. каждые 1-2 ч по необходимости, но не более 8 таб.сут.
Дети в возрасте 4-12 лет назначают до 4 таб.сут.', TRUE, TRUE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От боли в горле', 'Russia', 'Россия', 'Мирамистин', 'Мирамистин',
        'Антисептическое средство, которое используется для лечения инфекций горла и полости рта. Он обладает широким спектром действия против бактерий, грибков и вирусов. Миромистин применяется для полоскания горла и лечения различных инфекций.', 'Оториноларингология комплексное лечение острого и хронического наружного отита, гайморита, тонзиллита, фарингита, ларингита.
Стоматология лечение и профилактика инфекционно-воспалительных заболеваний полости рта стоматитов, гингивитов, пародонтитов. Гигиеническая обработка съемных протезов.', 'Повышенная чувствительность к действующему веществу.
Не рекомендуется применение препарата в форме спрея для орошения горла и миндалин детям в возрасте до 3 лет ввиду риска реактивного ларингоспазма.', 'При остром и хроническом наружном отите в наружный слуховой проход с помощью пипетки закапывают до 5 капель препарата 4 раза в сутки Курс лечения - 10 дней.
Тонзиллиты, фарингиты, ларингиты
Дети 3-6 лет однократным нажатием на головку насадки-распылителя или 3- 5 мл на одно полоскание, 3-4 раза в сутки;
Дети 7-14 лет двукратным нажатием на головку насадки-распылителя или 5- 7 мл на одно полоскание, 3-4 раза в сутки;
Дети старше 14 лет и взрослые 3-4-х кратным нажатием на головку насадки- распылителя или 10-15 мл на одно полоскание, 3-4 раза в сутки.',
        TRUE, TRUE, TRUE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
