                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противокашлевые', 'Russia', 'Россия', 'Лазолван', 'Амброксол',
        'Раствор для приема внутрь и ингаляций. Лекарственное средство, предназначенное для улучшения рыхлительных и отхаркивающих свойств секретов, которые накапливаются в дыхательных путях.',
        'Острые и хронические заболевания дыхательных путей с выделением вязкой мокроты острый и хронический бронхит, пневмония, хроническая обструктивная болезнь легких, бронхиальная астма с затруднением отхождения мокроты, бронхоэктатическая болезнь.',
        'Повышенная чувствительность к амброксолу или другим компонентам препарата, беременность (I триместр), период лактации.', 'Внутрь.
Прием внутрь (1 мл = 25 капель).
Взрослым и детям старше 12 лет 4 мл (= 100 капель) 3 раза в сутки.
детям от 6 до 12 лет 2 мл (= 50 капель) 2-3 раза в сутки;
детям от 2 до 6 лет 1 мл (= 25 капель); 3 раза в сутки;
детям до 2 лет 1 мл (= 25 капель) 2 раза в сутки.

Ингаляции
Взрослым и детям старше 6 лет 1 -2 ингаляции по 2-3 мл раствора в сутки.
Детям до 6 лет 1-2 ингаляции по 2 мл раствора в сутки.', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противокашлевые', 'Russia', 'Россия', 'Амбробене', 'Амброксол',
        'Раствор для приема внутрь и ингаляций. Муколитический и отхаркивающий препарат',
        'Заболевания дыхательных путей, сопровождающиеся нарушением образования и отхождения мокроты, кашель, сухой кашель', '- Повышенная чувствительность к амброксолу или к одному из вспомогательных веществ;
- беременность (I триместр);
- дефицит сахаразыизомальтазы, непереносимость фруктозы, глюкозо-галактозная мальабсорбция.
С осторожностью
Нарушение моторной функции бронхов и повышенное образование мокроты (при синдроме неподвижных ресничек), язвенная болезнь желудка и 12-перстной кишки в период обострения, беременность (II-III триместр), период лактации.
Пациенты с нарушениями функции почек или тяжелыми заболеваниями печени должны принимать Амбробене с особой осторожностью, соблюдая большие интервалы между приемами или принимая препарат в меньшей дозе.', 'Сироп следует принимать после еды, используя прилагаемый мерный стаканчик.
Детям до 2 лет следует принимать по 12 мерного стаканчика (2,5 мл сиропа) 2 раза в день (15 мг амброксола в день).
Детям от 2 до 6 лет следует принимать по 12 мерного стаканчика (2,5 мл сиропа) 3 раза в день (22,5 мг амброксола в день).
Детям от 6 до 12 лет следует принимать по 1 мерному стаканчику (5 мл сиропа) 2-3 раза в день (30 - 45 мг амброксола в день).
Взрослым и детям старше 12 лет в первые 2-3 дня лечения следует принимать по 2 мерных стаканчика (10 мл сиропа) 3 раза в день (90 мг амброксола в день).',
        FALSE, FALSE, FALSE, TRUE, TRUE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
