VALUES ('Противокашлевые', 'Russia', 'Россия', 'Аскорил', 'Бромгексин, гвайфенезин, сальбутамол',
        'Рецептурный лекарственный препарат. Аскорил — это комбинированный препарат, который обычно используется для лечения заболеваний дыхательной системы.',
        'Туберкулез, коклюш, бронхиальная астма, трахеобронхит, бронхит, пневмокониоз, пневмония, эмфизема легких', '- Повышенная чувствительность к компонентам препарата;
- беременность, период лактации;
- тахиаритмия, миокардит;
- пороки сердца;
- декомпенсированный сахарный диабет;
- тиреотоксикоз;
- глаукома;
- печеночная или почечная недостаточность;
- язвенная болезнь желудка и двенадцатиперстной кишки в стадии обострения;
- желудочное кровотечение;
- артериальная гипертензия;
- детский возраст до 6-х лет.',
        'Внутрь. Взрослым и детям старше 12 лет назначают по 1 таблетке 3 разасутки. Детям в возрасте от 6 лет до 12 лет - по ½ или 1 таблетке 3 разасутки.',
        FALSE, FALSE, FALSE, FALSE, FALSE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противовирусные', 'Russia', 'Россия', 'Ингавирин', 'Имидазолилэтанамид',
        'Противовирусный препарат, который используется для лечения острых респираторных вирусных инфекций (ОРВИ) и гриппа. Он обладает иммуномодулирующим действием и помогает организму бороться с вирусами.',
        'Для дозировки 60 мг лечение гриппа А и В и других острых респираторных вирусных инфекций (аденовирусная инфекция, парагрипп, респираторно-синцитиальная инфекция) у детей от 13 до 17 лет. Для дозировки 90 мг30 мг лечение и профилактика гриппа А и В и других острых респираторных вирусных инфекций (аденовирусная инфекция, парагрипп, респираторно-синцитиальная инфекция, риновирусная инфекция) у взрослых и детей от 3 лет.', 'Дефицит лактазы, непереносимость лактозы, глюкозо-галактозная мальабсорбция.
Беременность.
Период грудного вскармливания.
Детский возраст до 3 лет.', 'Для дозировки 60 мг Внутрь. Независимо от приема пищи. Для лечения гриппа и острых респираторных вирусных инфекций детям от 7 до 17 лет назначают по 1 капсуле (60 мг) 1 раз в день. Длительность лечения 5-7 дней (в зависимости от тяжести состояния). Прием препарата начинают с момента появления первых симптомов заболевания, желательно не позднее 2 суток от начала болезни.
Для лечения и профилактики гриппа и острых респираторных вирусных инфекций взрослым назначают по 90 мг 1 раз в день, детям от 7 лет - по 60 мг 1 раз в день, детям от 3 до 6 лет - по 30 мг 1 раз в день.',
        TRUE, FALSE, FALSE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противовирусные', 'Russia', 'Россия', 'Виферон', 'Интерферон альфа-2b',
        'Лекарственный препарат, содержащий интерферон альфа-2b, который используется для лечения различных вирусных инфекций. Он обладает иммуностимулирующим действием, помогающим организму бороться с вирусами.',
        'Герпес, инфекционно-воспалительные заболевания, лечение инфекций, вызванных вирусом простого герпеса (ВПГ), хронические гепатиты, инфекции кожи и слизистых оболочек, вызванные вирусом герпеса, ОРВИ, инфекционно-воспалительные заболевания органов малого таза, генитальный герпес',
        'Повышенная чувствительность к любому из компонентов препарата.', 'Препарат применяют ректально. 1 суппозиторий содержит в качестве активного вещества интерферон альфа-2b человеческий рекомбинантный в указанных дозировках (150000 ME, 500000 ME, 1000000 ME, 3000000 ME).
В комплексной терапии различных инфекционно-воспалительных заболеваний у новорожденных детей, в том числе недоношенных новорожденным, в том числе недоношенным детям с гестационным возрастом более 34 недель, назначают ВИФЕРОН 150000 ME ежедневно по 1 суппозиторию 2 раза в сутки через 12 ч. Курс лечения - 5 суток.',
        TRUE, TRUE, TRUE, TRUE, TRUE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противовирусные', 'Russia', 'Россия', 'Арбидол', 'Умифеновир',
        'Противовирусный препарат, который используется для профилактики и лечения вирусных инфекций, таких как грипп и другие острые респираторные вирусные инфекции (ОРВИ). Он обладает иммуномодулирующим действием и помогает организму бороться с вирусами.', 'Профилактика и лечение у взрослых и детей грипп А и В, другие ОРВИ.
Комплексная терапия рецидивирующей герпетической инфекции.
Профилактика послеоперационных инфекционных осложнений.
Комплексная терапия острых кишечных инфекций ротавирусной этиологии у детей старше 6 лет.',
        'Повышенная чувствительность к умифеновиру или любому компоненту препарата; детский возраст до 6 лет. Первый триместр беременности. Период грудного вскармливания.', 'Дети с 6 до 12 лет 100 мг (1 капсула); Дети старше 12 лет и взрослые 200 мг (2 капсулы);
У детей с 6 лет и взрослых Неспецифическая профилактика в разовой дозе период эпидемии гриппа и других ОРВИ 2 раза в неделю в течение 3-х недель. Неспецифическая профилактика при непосредственном контакте с больными гриппом и другими ОРВИ в разовой дозе 1 раз в день в течение 10-14 дней.
Лечение гриппа и других ОРВИ в разовой дозе 4 раза в сутки (каждые 6 часов) в течение 5 суток. Комплексная терапия рецидивирующей герпетической инфекции в разовой дозе 4 раза в сутки (каждые 6 часов) в течение 5-7 суток, затем разовую дозу 2 раза в неделю в течение 4-х недель.',
        TRUE, FALSE, FALSE, TRUE, FALSE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противовирусные', 'Russia', 'Россия', 'Кагоцел', 'Кагоцел',
        'Препарат, который помогает укрепить иммунную систему и повысить ее защитные функции. Компоненты, входящие в состав препарата, применяются для лечения гриппа и ОРВИ.',
        'Профилактика и лечение гриппа и других ОРВИ у взрослых и детей в возрасте от 36 месяцев; — лечение герпеса у взрослых.',
        'Беременность; период лактации (грудного вскармливания); детский возраст до 3 лет; дефицит лактазы, непереносимость лактозы, глюкозо-галактозная мальабсорбция; повышенная чувствительность к компонентам препарата.', 'Внутрь, независимо от приема пищи. Для лечения гриппа и ОРВИ взрослым назначают в первые два дня - по 2 таблетки 3 раза в день, в последующие два дня - по одной таблетке 3 раза в день. Всего на курс - 18 таблеток, длительность курса - 4 дня.

Для лечения герпеса у взрослых назначают по 2 таблетки 3 раза в день в течение 5 дней. Всего на курс - 30 таблеток, длительность курса - 5 дней.
Для лечения гриппа и ОРВИ детям в возрасте от 3 до 6 лет назначают в первые два дня - по 1 таблетке 2 раза в день, в последующие два дня - по одной таблетке 1 раз в день. Всего на курс - 6 таблеток, длительность курса - 4 дня.',
        TRUE, FALSE, FALSE, TRUE, FALSE, TRUE);
