VALUES ('Спазмолитики', 'Russia', 'Россия', 'Дротаверин', 'Дротаверин',
        'Лекарственный препарат, основным действующим компонентом которого является дротаверин гидрохлорид. Он имеет миотропное действие и способствует расслаблению гладких мышц внутренних органов', '- Спазм гладкой мускулатуры при заболеваниях желчевыводящих путей холецистолитиаз, холангиолитиаз, холецистит, перихолецистит, холангит, воспаление сосочка двенадцатиперстной кишки;
- Спазм гладкой мускулатуры при заболеваниях мочевыводящих путей нефролитиаз, уретролитиаз, пиелит, цистит, спазм мочевого пузыря;', '- Повышенная чувствительность к дротаверину иили вспомогательным веществам, входящим в состав препарата;
- тяжелая печеночная или почечная недостаточность;
- тяжелая сердечная недостаточность (синдром низкого сердечного выброса);
- период грудного вскармливания;
- детский возраст (до 6 лет);
- наследственная непереносимость лактозы, недостаточность лактазы или синдром мальабсорбции глюкозыгалактозы.', 'Внутрь.
Взрослые но 40 - 80 мг (1-2 таблетки) 2-3 раза в сутки. Максимальная разовая доза - 80 мг, максимальная суточная доза - 240 мг.
Дети в возрасте от 6 до 12 лет максимальная суточная доза составляет 80 мг, разделенная на 2 приема.
Дети старше 12 лет - максимальная суточная доза составляет 160 мг, разделенная на 2-4 приема.
Рекомендуемая продолжительность лечения без консультации врача 1-2 дня.', FALSE, FALSE, FALSE, FALSE, FALSE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Спазмолитики', 'Russia', 'Россия', 'Спазмалгон', 'Метамизол натрия, папаверин, бендазол',
        'Комбинированный препарат, который используется для устранения болевых симптомов при спазмах гладкой мускулатуры органов брюшной полости, желчевыводящих путей и мочевыводящих путей.',
        'Болевой синдром (слабо или умеренно выраженный) при спазмах гладкой мускулатуры внутренних органов почечная колика, спазм мочеточников и мочевого пузыря; желчная колика, кишечная колика, дискинезия желчевыводящих путей, постхолецистэктомический синдром, хронический колит; альгодисменорея, заболевания органов малого таза.',
        'Гиперчувствительность к компонентам препарата и другим производным пиразолона, угнетение костномозгового кроветворения, выраженная печеночная иили почечная недостаточность, дефицит глюкозо-6-фосфатдегидрогеназы, тахиаритмии, тяжелая стенокардия, декомпенсированная хроническая сердечная недостаточность, закрытоугольная глаукома, гиперплазия предстательной железы (с клиническими проявлениями), кишечная непроходимость, мегаколон, коллапс, беременность (особенно в I триместре и в последние 6 недель), период лактации, детский возраст до 15 лет.',
        'Внутримышечно по 2-5 мл инъекционного раствора 2-3 раза в сутки. Перед введением инъекционного раствора его следует согреть в руке. Продолжительность лечения - не более 5 дней. Максимальная суточная доза не должна превышать 10 мл инъекционного раствора (соответственно 5 г метамизола натрия). При отсутствии терапевтического эффекта применение препарата прекращается, а при хорошем или удовлетворительном эффекте переходят к пероральному или ректальному применению. Продолжительность лечебного курса определяется в зависимости от клинической симптоматики и этиопатогенеза заболевания.',
        FALSE, FALSE, FALSE, FALSE, FALSE, FALSE);
