VALUES ('От запора', 'Russia', 'Россия', 'Фитолакс',
        'Листья сенны, экстракт сенны сухой, абрикосы, листья подорожника, плоды укропа.',
        'БАД. Растительный препарат, предназначенный для улучшения работы кишечника и облегчения запоров.', 'Биологически активная добавка Фитолакс рекомендуется в качестве мягкого послабляющего средства, может назначаться самостоятельно или в составе комплексных схем при
Запорах, вне зависимости от их причины.
Сниженной моторике кишечника.
Нарушениях пищеварения.', 'Индивидуальная непереносимость компонентов, беременность, кормление грудью.', 'Взрослым и детям старше 14 лет по 2 таблетки вечером во время еды. Таблетки следует разжевать. Слабительное действие наступает через 8-12 часов. При необходимости разовый прием можно увеличить до 4 таблеток.
Продолжительность приема 2 недели.
При необходимости курс приема можно повторять', TRUE, FALSE, FALSE, TRUE, TRUE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От запора', 'Russia', 'Россия', 'Гутталакс', 'Натрия пикосульфата моногидрат',
        'Лекарственный препарат. Слабительное средство, которое используется для лечения запоров', 'В качестве слабительного средства в следующих случаях
- запоры, обусловленные атонией и гипотонией толстой кишки (в том числе в пожилом возрасте, у лежачих больных, после операций, после родов и в период лактации)
- запоры, вызванные приемом лекарственных средств
- для регулирования стула при геморрое, проктите, анальных трещинах (для размягчения консистенции кала)
- заболевания желчного пузыря, синдром раздраженной кишки с преобладанием запоров
- запор, обусловленный дисбактериозом кишечника, нарушениями диеты.', 'Кишечная непроходимость или обструктивные заболевания кишечника;
- острые заболевания органов брюшной полости или сильная боль в животе, которые могут сопровождаться тошнотой, рвотой, повышением температуры тела, включая аппендицит;
- острые воспалительные заболевания кишечника;
- повышенная чувствительность к натрию пикосульфату или другим компонентам препарата;
- тяжелая дегидратация;
- непереносимость фруктозы.
Детский возраст до 4 лет.', 'Внутрь.
Рекомендуется следующий режим дозирования
Взрослые и дети старше 10 лет 10-20 капель (5-10 мг) в сутки
Дети 4-10 лет 5-10 капель (2,5-5 мг) в сутки
Рекомендуется начинать с наименьшей дозы. Для того чтобы достичь регулярного стула, доза может повышаться до максимальной рекомендуемой. Не следует превышать максимальную рекомендуемую суточную дозу.
Рекомендуемая доза для детей младше 4 лет составляет 0,25 мгкг массы тела в сутки. Это соответствует 1 капле препарата (0,5 мг натрия пикосульфата) на 2 кг массы тела в сутки. Для получения слабительного эффекта в утренние часы следует принимать препарат накануне на ночь. Препарат не обязательно растворять в жидкости.',
        TRUE, FALSE, FALSE, TRUE, FALSE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('От запора', 'Russia', 'Россия', 'Дюфалак', 'Лактулоза',
        'Лекарственный препарат, содержащий лактулозу, который используется для лечения запоров.', 'Запор регуляция физиологического ритма опорожнения толстой кишки.
- Размягчение стула в медицинских целях (геморрой, состояния после операции на толстой кишке и в области анального отверстия).
- Печеночная энцефалопатия у взрослых лечение и профилактика печеночной комы или прекомы.', 'Галактоземия;
- непроходимость, перфорация или риск перфорации желудочно-кишечного тракта;
- повышенная чувствительность к любому компоненту препарата;
- непереносимость галактозы или фруктозы, дефицит лактазы или глюкозо- галактозная мальабсорбция.', 'Доза при лечении запора или для размягчения стула в медицинских целях
Суточную дозу лактулозы можно принимать однократно, либо разделив ее на две,используя мерный стаканчик.
Через несколько дней начальная доза может быть скорректирована до поддерживающей дозы в зависимости от реакции на прием препарата. Слабительный эффект может проявиться через 2-3 дня после начала приема препарата. Если поддерживающая суточная доза меньше 15 мл, а также для точного дозирования у детей до 7 лет рекомендуется применять препарат во флаконах.
Доза при лечении печеночной энцефалопатии (взрослые)
Начальная доза 3-4 раза в день по 30-45 мл.
Затем переходят на индивидуально подобранную поддерживающую дозу так, чтобы мягкий стул был максимально 2-3 раза в день.',
        TRUE, TRUE, TRUE, TRUE, TRUE, FALSE);
