                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противовоспалительные', 'Russia', 'Россия', 'Диклофенак', 'Диклофенак',
        'Раствор для инъекций.Лекарственный препарат. Артрит, анкилозирующий спондилит, подагра, остеоартроз, люмбаго, ишиас, невралгия, менструальные боли, аднексит, почечные колики', 'Доза при лечении печеночной энцефалопатии (взрослые)
Для приема внутрь
Начальная доза 3-4 раза в день по 30-45 мл.
Затем переходят на индивидуально подобранную поддерживающую дозу так, чтобы мягкий стул был максимально 2-3 раза в день.',
        'Гиперчувствительность, тяжелая печеночная недостаточность или заболевания печени в острый период, тяжелая почечная недостаточность, прогрессирующие заболевания почек, гиперкалиемия; бронхообструкция, ринит, крапивница, спровоцированные приемом ацетилсалициловой кислоты или др. НПВП (в т. ч. в анамнезе); нарушение кроветворения, нарушения гемостаза (в т. ч. гемофилия), беременность, детский возраст (до 18 лет), период грудного вскармливания, период после проведения аортокоронарного шунтирования, подтвержденная хроническая сердечная недостаточность (II-IV функционального класса по классификации NYHA), ишемическая болезнь сердца, заболевания периферических артерий или цереброваскулярные заболевания; неконтролируемая артериальная гипертензия.', 'Инъекционный раствор вводится глубоко внутримышечно (в верхний наружный квадрант ягодичной области). Разовая доза для взрослых - 75 мг (1 ампула). При необходимости возможно повторное введение, но не ранее, чем через 12 часов. Вторая инъекция должна проводиться в противоположную ягодичную область.
Максимальная рекомендуемая суточная доза препарата Диклофенак раствор для внутримышечного введения составляет 150 мг. Длительность использования не более 2 дней, при необходимости далее переходят на пероральное, либо ректальное применение диклофенака.',
        FALSE, FALSE, FALSE, TRUE, FALSE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противовоспалительные', 'Russia', 'Россия', 'Ибупрофен', 'Ибупрофен',
        'Лекарственный препарат. Таблетки. Нестероидное противовоспалительное средство (НПВС), которое используется для уменьшения боли, воспаления и жара.',
        'Ревматоидный артрит, остеоартроз, суставной синдром при обострении подагры, псориатический артрит, болезнь Бехтерева , цервикальный спондилез, синдром Барре-Льеу; невралгия, миалгия, тендинит, бурсит, тендовагинит, невралгическая амиотрофия, растяжение связочного аппарата, гематомы, радикулит, травматическое воспаление мягких тканей и опорно-двигательного аппарата; лихорадочные состояния различного генеза ;симптоматическое лечение гриппа и ОРВИ; постуральная гипотензия при приеме гипотензивных средств; нефротический синдром (для уменьшения выраженности протеинурии). Как вспомогательное средство инфекционно-воспалительные заболевания ЛОР-органов , бронхит, пневмония, воспалительные процессы в малом тазу, аднексит, первичная дисменорея, альгодисменорея, послеоперационные боли, головная и зубная боль, панникулит.', 'Гиперчувствительность к ибупрофену или любому из компонентов, входящих в состав препарата.
Полное или неполное сочетание бронхиальной астмы, рецидивирующего полипоза носа и околоносовых пазух, и непереносимости ацетилсалициловой кислоты или других НПВП (в том числе в анамнезе).
Эрозивно-язвенные заболевания органов ЖКТ
Кровотечение или перфорация язвы органов ЖКТ в анамнезе, спровоцированные применением НПВП.
Тяжелая сердечная недостаточность
Тяжелая печеночная недостаточность или заболевание печени в активной фазе.
Почечная недостаточность тяжелой степени тяжести (клиренс креатинина 30 млмин).
Подтвержденная гиперкалиемия.
Декомпенсированная сердечная недостаточность; период после проведения аортокоронарного шунтирования.
Цереброваскулярное или иное кровотечение (в том числе внутричерепное кровоизлияние).
Гемофилия и другие нарушения свертываемости крови (в том числе гипокоагуляция), геморрагические диатезы.
Беременность (III триместр).
Детский возраст до 6 лет.', 'Внутрь, после еды. Взрослым при остеоартрозе, псориатическом артрите и анкилозирующем спондилите - по 400 - 600 мг 3 - 4 раза в сутки. При ревматоидном артрите - по 800 мг 3 раза в сутки; при травмах мягких тканей, повреждениях связок - 1,6 - 2,4 гсут в несколько приемов. При первичной дисменорее - по 400 мг 3 - 4 раза в сутки; при умеренном болевом синдроме - 1,2 гсут.
Детям старше 12 лет начальная доза - 150 - 300 мг 3 раза в сутки; максимальная доза - 1 г, затем - 100 мг 3 раза в сутки; при ювенильном ревматоидном артрите -30 - 40 мгкгсут в несколько приемов. Для снижения температуры тела 39,2 °C и выше - 10 мгкгсут, ниже 39,2 °C - 5 мгкгсут.',
        FALSE, FALSE, FALSE, FALSE, FALSE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
                        liver_friendly, child_friendly, stomach_friendly)
VALUES ('Противовоспалительные', 'Russia', 'Россия', 'Нимесил', 'Нимесилид',
        'Лекарственный препарат. Он относится к группе нестероидных противовоспалительных средств (НПВС) и используется для снятия боли и воспаления, а также для лечения различных заболеваний, таких как остеоартрит, остеохондроз и другие.', '- Лечение острой боли (в т.ч. боли в спине, пояснице; болевой синдром в костно-мышечной системе, включая ушибы, растяжения связок и вывихи суставов; тендиниты, бурситы; зубная боль);
- симптоматическое лечение остеоартроза (остеоартрита) с болевым синдромом;
- первичная альгодисменорея.', 'Гиперчувствительность к нимесулиду или другим компонентам препарата;
гиперергические реакции в анамнезе ;
полное или неполное сочетание бронхиальной астмы, рецидивирующего полипоза носа или околоносовых пазух с непереносимостью ацетилсалициловой кислоты и других МПВП (в том числе в анамнезе);
гепатотоксические реакции на нимесулид в анамнезе;
одновременное применение с другими лекарственными препаратами с потенциальной гепатотоксичностью (например, другими НПВП);
хронические воспалительные заболевания кишечника (болезнь Крона, язвенный колит) в фазе обострения
период после проведения аортокоронарного шунтирования;
лихорадочный синдром при простуде и острых респираторно-вирусных инфекциях;
подозрение на острую хирургическую патологию;
язвенная болезнь желудка или двенадцатиперстной кишки в фазе обострения; эрозивно-язвенное поражение желудочно-кишечного тракта; перфорации или желудочно-кишечные кровотечения в анамнезе;
цереброваскулярные кровотечения в анамнезе или другие заболевания, сопровождающиеся повышенной кровоточивостью;
тяжелые нарушения свертывания крови;
тяжелая сердечная недостаточность;
тяжелая почечная недостаточность (клиренс креатинина 30 млмин), подтвержденная гиперкалиемия;
печеночная недостаточность или любое активное заболевание печени;
детский возраст до 12 лет;
беременность и период грудного вскармливания;
алкоголизм, наркотическая зависимость;
наследственная непереносимость фруктозы, дефицит сахаразы-изомальтазы и синдром мальабсорбции глюкозы-галактозы.', 'Внутрь. Содержимое пакетика растворить в стакане негазированной воды (приблизительно 100 мл), перемешать до получения суспензии с апельсиновым запахом. Суспензию необходимо употребить сразу после приготовления.
Взрослым и детям старше 12 лет (масса тела более 40 кг) по 1 пакетику (100 мг нимесулида) два раза в сутки, после еды.
Пациенты пожилого возраста при лечении пациентов пожилого возраста нет необходимости в корректировке суточной дозы (см. раздел «Фармакокинетика»).
Применение у детей
Дети в возрасте 12 - 18 лет корректировка дозы не требуется с учетом фармакокинетических и фармакодинамических характеристик нимесулида.
Дети в возрасте до 12 лет применение препаратов, содержащих нимесулид, противопоказано.
Максимальная суточная доза для взрослых и детей старше 12 лет составляет 200 мг. Максимальная продолжительность курса лечения препаратом Нимесил® - 15 дней.',
        FALSE, FALSE, FALSE, FALSE, FALSE, FALSE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
                        contraindications, dosing, kidney_friendly, pregnant_friendly, breastfed_friendly,
