VALUES ('Обработка ран', 'Russia', 'Россия', 'Хлоргексидин', 'Хлоргексидин',
        'Антисептическое средство, которое используется для дезинфекции кожи и слизистых оболочек.',
        'Профилактика инфекций, передаваемых половым путем (хламидиоз, уреаплазмоз, трихомониаз, гонорея, сифилис, генитальный герпес). Дезинфекция гнойных ран, инфицированных ожоговых поверхностей; лечение инфекций кожи и слизистых оболочек в хирургии, в акушерстве и гинекологии, урологии (уретриты, уретропростатиты), стоматологии (гингивит, стоматит, афты, пародонтит, альвеолит).',
        'Гиперчувствительность, дерматит.', 'Наружно. Местно. Применяется в виде орошений, полосканий и аппликаций - 5-10 мл препарата наносят на пораженную поверхность кожи или слизистых оболочек с экспозицией 1-3 мин 2-3 раза в сутки (на тампоне или путем орошения).
Для профилактики заболеваний, передающихся половым путем, препарат эффективен, если он применяется не позднее 2 ч после полового акта. Содержимое флакона ввести в мочеиспускательный канал мужчинам (2-3 мл), женщинам (1-2 мл) и во влагалище (5-10 мл) на 2-3 мин. Обработать кожу внутренних поверхностей бедер, лобка, половых органов. После процедуры не мочиться в течение 2 ч. Комплексное лечение уретритов и уретропростатитов проводят путем впрыскивания в уретру 2-3 мл 1-2 раза в день, курс - 10 дней, процедуры назначают через день.',
        TRUE, TRUE, TRUE, TRUE, TRUE, TRUE);
INSERT INTO ma_medicals(type, country_en, country_ru, name, active_ingredient, description, indications,
